module mux8to1 (
    input [7:0] mux_I, // 8 input lines
    input [2:0] S, // 3 selection lines
    output reg Y   // output line
);
    always @(*) begin
        case (S)
            3'b000: Y = mux_I[0];
            3'b001: Y = mux_I[1];
            3'b010: Y = mux_I[2];
            3'b011: Y = mux_I[3];
            3'b100: Y = mux_I[4];
            3'b101: Y = mux_I[5];
            3'b110: Y = mux_I[6];
            3'b111: Y = mux_I[7];
            default: Y = 1'b0; // default case
        endcase
    end
endmodule
